import { GoogleGenAI, Modality, Part, GenerateContentResponse, HarmCategory, HarmBlockThreshold, Type } from "@google/genai";
import { ImageFile, AudioFile } from '../types';

if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const safetySettings = [
  {
    category: HarmCategory.HARM_CATEGORY_HARASSMENT,
    threshold: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
  },
  {
    category: HarmCategory.HARM_CATEGORY_HATE_SPEECH,
    threshold: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
  },
  {
    category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT,
    threshold: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
  },
  {
    category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT,
    threshold: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
  },
];

const handleApiResponse = (response: GenerateContentResponse): ImageFile => {
    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            return {
                base64: part.inlineData.data,
                mimeType: part.inlineData.mimeType,
                name: 'generated-image.png',
            };
        }
    }

    const safetyText = response.candidates?.[0]?.finishReason;
    if (safetyText && safetyText !== 'STOP') {
        throw new Error(`Image generation failed due to safety settings: ${safetyText}`);
    }

    throw new Error('No image was generated by the model.');
};

export async function generateImage(
  productImages: ImageFile[],
  prompt: string,
  styleImage: ImageFile | null
): Promise<ImageFile> {
  const model = 'gemini-2.5-flash-image';

  const parts: Part[] = [];

  productImages.forEach(productImage => {
    parts.push({
      inlineData: {
        data: productImage.base64,
        mimeType: productImage.mimeType,
      },
    });
  });

  parts.push({ text: prompt });

  if (styleImage) {
    parts.push({
      inlineData: {
        data: styleImage.base64,
        mimeType: styleImage.mimeType,
      },
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: parts },
      config: {
        responseModalities: [Modality.IMAGE],
      },
      safetySettings: safetySettings,
    });

    return handleApiResponse(response);

  } catch (error) {
    console.error('Error calling Gemini API for generation:', error);
    let errorMessage = 'An unknown error occurred while generating the image.';
    if (error instanceof Error) {
        const msg = error.message.toLowerCase();
        if (msg.includes('api key not valid')) {
            errorMessage = 'Your API key is not valid. Please check your API key and try again.';
        } else if (msg.includes('quota')) {
            errorMessage = 'You have exceeded your API quota. Please check your billing account or try again later.';
        } else if (msg.includes('safety settings')) {
            errorMessage = `Image generation was blocked due to safety settings. Please adjust your prompt.`;
        } else if (msg.includes('400')) {
             errorMessage = 'The request was invalid (Bad Request). Please check the uploaded image and prompt.';
        } else if (msg.includes('500')) {
             errorMessage = 'The image generation service is currently unavailable (Server Error). Please try again later.';
        } else {
             errorMessage = `Failed to generate image. Details: ${error.message}`;
        }
    }
    throw new Error(errorMessage);
  }
}

