export async function analyzeImageForPrompt(
  images: ImageFile[],
  instructions: string
): Promise<string> {
  const model = 'gemini-2.5-flash';

  const parts: Part[] = [];

  images.forEach(image => {
    parts.push({
      inlineData: {
        data: image.base64,
        mimeType: image.mimeType,
      },
    });
  });

  let textPrompt = `Analyze the provided image(s) in detail. Based on your analysis, craft a comprehensive and descriptive prompt suitable for an advanced text-to-image AI model. The prompt should be a single, cohesive paragraph.

Your analysis should cover:
- **Subject:** What is the main subject? Describe its appearance, attire, and any actions.
- **Composition:** How is the shot framed (e.g., close-up, wide shot)? What is the angle?
- **Environment:** Describe the background, setting, and any notable objects.
- **Lighting:** Characterize the lighting (e.g., soft, dramatic, natural, studio).
- **Color Palette:** Describe the dominant colors and overall color scheme.
- **Style/Mood:** What is the artistic style (e.g., photorealistic, impressionistic) and the overall mood (e.g., serene, energetic, mysterious)?`;

  if (instructions) {
    textPrompt += `\n\nAdditionally, incorporate the following user instructions: "${instructions}"`;
  }

  textPrompt += `\n\nGenerate only the final prompt as a single block of text. Do not include headers, lists, or any text other than the prompt itself.`

  parts.push({ text: textPrompt });

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: { parts: parts },
      safetySettings: safetySettings,
    });

    if(!response.text) {
      const safetyText = response.candidates?.[0]?.finishReason;
      if (safetyText && safetyText !== 'STOP') {
          throw new Error(`Prompt generation failed due to safety settings: ${safetyText}`);
      }
      throw new Error('Model returned no text for the prompt.');
    }

    return response.text.trim();

  } catch (error) {
    console.error('Error analyzing image for prompt:', error);
    let errorMessage = 'An unknown error occurred while analyzing the image.';
    if (error instanceof Error) {
        const msg = error.message.toLowerCase();
        if (msg.includes('api key not valid')) {
            errorMessage = 'Your API key is not valid. Please check your API key and try again.';
        } else if (msg.includes('quota')) {
            errorMessage = 'You have exceeded your API quota. Please check your billing account or try again later.';
        } else if (msg.includes('safety settings')) {
            errorMessage = `Image analysis was blocked due to safety settings.`;
        } else {
             errorMessage = `Failed to analyze image. Details: ${error.message}`;
        }
    }
    throw new Error(errorMessage);
  }
}

