import React, { useCallback } from 'react';
import { CampaignStudioProject, ImageFile, CampaignResult, CampaignScenario } from '../types';
import { resizeImage } from '../utils';
import { analyzeProductForCampaign, generateImage, editImage } from '../services/geminiService';
import ImageUploader from './ImageUploader';
import BrandingResultsGrid from './BrandingResultsGrid'; // Resuing similar grid layout

const CAMPAIGN_SCENARIOS: CampaignScenario[] = [
    'Lifestyle Context', 'In-Action Usage', 'POV Hand-Held', 
    'Creative Flat Lay', 'Dynamic Outdoor', 'Detail Close-up'
];

// Helper to construct prompts based on the analyzed product context + fixed social media archetypes
const getCampaignPrompt = (scenario: CampaignScenario, productContext: string): string => {
    const baseRequirement = `Create a high-quality, professional Social Media Portrait (9:16 aspect ratio) featuring the product described as: "${productContext}". Do not include any text or logos overlay. `;

    switch (scenario) {
        case 'Lifestyle Context':
            return baseRequirement + `Scene: Place the product in its ideal natural environment (e.g., a home, office, or studio) where it belongs. The lighting should be natural and inviting. The mood is aspirational. Focus on how the product fits into a daily routine.`;
        case 'In-Action Usage':
            return baseRequirement + `Scene: Show the product being actively used by a human model (focus on hands or side profile, keeping the product as the hero). For example, if it's skincare, show it being applied; if it's a gadget, show it in operation. The shot should feel candid and authentic.`;
        case 'POV Hand-Held':
            return baseRequirement + `Scene: A first-person Point of View (POV) shot holding the product against a blurred, aesthetic background relevant to the product's niche. The focus is sharp on the product in the hand. Ideal for an Instagram Story style.`;
        case 'Creative Flat Lay':
            return baseRequirement + `Scene: An artistic top-down flat lay composition. Arrange the product with complementary props (ingredients, tools, or decor items) on a textured surface. The composition should be balanced and aesthetically pleasing for a Pinterest-style post.`;
        case 'Dynamic Outdoor':
            return baseRequirement + `Scene: Take the product outside. Capture it with natural sunlight, dynamic shadows, and an outdoor background (e.g., street, park, nature, or sky). The angle should be slightly low to make the product look heroic and impactful.`;
        case 'Detail Close-up':
            return baseRequirement + `Scene: An extreme close-up (macro shot) focusing on the texture, material, and premium details of the product. The depth of field should be shallow (bokeh effect) to blur the background completely. Highlight the quality of the build or ingredients.`;
        default:
            return baseRequirement;
    }
};

const CampaignStudio: React.FC<{
    project: CampaignStudioProject;
    setProject: React.Dispatch<React.SetStateAction<CampaignStudioProject>>;
}> = ({ project, setProject }) => {

    const handleFileUpload = async (files: File[]) => {
        if (!files || files.length === 0) return;
        const file = files[0];

        setProject(s => ({ ...s, isUploading: true, error: null }));
        try {
            if (!file.type.startsWith('image/')) {
                throw new Error(`File '${file.name}' is not a supported image type.`);
            }
            const resizedFile = await resizeImage(file, 1024, 1024);
            const reader = new FileReader();
            reader.onloadend = () => {
                const base64String = reader.result as string;
                setProject(s => ({
                    ...s,
                    productImage: { base64: base64String.split(',')[1], mimeType: resizedFile.type, name: resizedFile.name },
                    isUploading: false,
                    results: [], // Reset results on new upload
                    productAnalysis: null,
                }));
            };
            reader.onerror = () => { throw new Error(`Error reading file '${resizedFile.name}'.`); };
            reader.readAsDataURL(resizedFile);
        } catch (err) {
            console.error(err);
            const errorMessage = err instanceof Error ? err.message : 'Could not process file.';
            setProject(s => ({ ...s, error: errorMessage, isUploading: false }));
        }
    };

    const handleRemoveImage = () => {
        setProject(s => ({ ...s, productImage: null, results: [], productAnalysis: null, error: null }));
    };

    const onGenerate = useCallback(async () => {
        if (!project.productImage) {
            setProject(s => ({ ...s, error: 'Please upload a product image first.' }));
            return;
        }

        setProject(s => ({ ...s, isAnalyzing: true, isGenerating: true, error: null, results: [] }));

        try {
            // 1. Analyze the product
            let analysis = project.productAnalysis;
            if (!analysis) {
                analysis = await analyzeProductForCampaign(project.productImage);
                setProject(s => ({ ...s, productAnalysis: analysis, isAnalyzing: false }));
            } else {
                setProject(s => ({ ...s, isAnalyzing: false }));
            }

            // 2. Initialize placeholders
            const initialResults = CAMPAIGN_SCENARIOS.map(scenario => ({
                scenario, image: null, isLoading: true, error: null, editPrompt: '', isEditing: false
            } as any)); // cast to match generic structure if needed, or update types

            // Map Campaign Result to structure compatible with grid if needed, or just use specific types
            setProject(s => ({ ...s, results: initialResults }));

            // 3. Generate images in parallel
            const generationPromises = CAMPAIGN_SCENARIOS.map(scenario => {
                const prompt = getCampaignPrompt(scenario, analysis!);
                // We pass the product image as reference
                return generateImage([project.productImage!], prompt, null)
                    .then(image => ({ status: 'fulfilled' as const, value: { scenario, image } }))
                    .catch(error => ({ status: 'rejected' as const, reason: { scenario, error } }));
            });

            const settledResults = await Promise.all(generationPromises);

            settledResults.forEach(result => {
                if (result.status === 'fulfilled') {
                    const { scenario, image } = result.value;
                    setProject(s => ({
                        ...s,
                        results: s.results.map(r => r.scenario === scenario ? { ...r, image, isLoading: false } : r)
                    }));
                } else {
                    const { scenario, error } = result.reason;
                    setProject(s => ({
                        ...s,
                        results: s.results.map(r => r.scenario === scenario ? { ...r, error: error.message || 'Failed', isLoading: false } : r)
                    }));
                }
            });

        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : 'An error occurred during campaign generation.';
            setProject(s => ({ ...s, error: errorMessage, isAnalyzing: false }));
        } finally {
            setProject(s => ({ ...s, isGenerating: false }));
        }

    }, [project.productImage, project.productAnalysis, setProject]);

    // Reuse existing grid logic but adapt for CampaignResult type compatibility
    // Since BrandingResult and CampaignResult are structurally identical for the grid purpose (category/scenario -> string label)
    // We can cast or create a wrapper. Here we cast scenario to category for the grid.

    const handleImageEdit = async (scenario: CampaignScenario) => {
        const resultToEdit = project.results.find(r => r.scenario === scenario);
        if (!resultToEdit || !resultToEdit.image || !resultToEdit.editPrompt.trim()) return;

        setProject(s => ({ ...s, results: s.results.map(r => r.scenario === scenario ? { ...r, isEditing: true, error: null } : r) }));
        try {
            const newImage = await editImage(resultToEdit.image, resultToEdit.editPrompt);
            setProject(s => ({ ...s, results: s.results.map(r => r.scenario === scenario ? { ...r, image: newImage, isEditing: false, editPrompt: '' } : r) }));
        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : 'Edit failed.';
            setProject(s => ({ ...s, results: s.results.map(r => r.scenario === scenario ? { ...r, error: errorMessage, isEditing: false } : r) }));
        }
    };

    const handleSetEditPrompt = (scenario: CampaignScenario, prompt: string) => {
        setProject(s => ({ ...s, results: s.results.map(r => r.scenario === scenario ? { ...r, editPrompt: prompt } : r) }));
    };

    return (
        <main className="w-full max-w-7xl flex flex-col gap-4 pt-4 pb-8 flex-grow">
            {/* Header & Upload */}
            <div className="glass-card rounded-2xl p-4 flex flex-col md:flex-row items-center gap-4">
                <div className="w-full md:w-48 flex-shrink-0">
                    <ImageUploader
                        id="campaign-uploader"
                        title="Product Image"
                        images={project.productImage ? [project.productImage] : []}
                        onFileUpload={handleFileUpload}
                        onRemove={handleRemoveImage}
                        isUploading={project.isUploading}
                    />
                </div>
                <div className="flex-grow text-center md:text-left">
                    <h2 className="text-xl font-bold text-[var(--color-text-base)]">Social Campaign Studio</h2>
                    <p className="text-md text-[var(--color-text-secondary)] mt-1">
                        Upload a product photo. AI will analyze it and generate 6 professional lifestyle and action shots for your social media campaign.
                    </p>
                    {project.productAnalysis && (
                        <div className="mt-2 text-xs text-[var(--color-accent)] bg-[rgba(var(--color-accent-rgb),0.1)] p-2 rounded-lg border border-[rgba(var(--color-accent-rgb),0.2)]">
                            <strong>AI Analysis:</strong> {project.productAnalysis}
                        </div>
                    )}
                </div>
                <button
                    onClick={onGenerate}
                    disabled={!project.productImage || project.isGenerating || project.isUploading}
                    className="w-full md:w-auto flex-shrink-0 bg-gradient-to-r from-[var(--color-accent)] to-[var(--color-accent-dark)] hover:from-[var(--color-accent-dark)] hover:to-[var(--color-accent-darker)] text-[var(--color-text-base)] font-bold py-3 px-8 rounded-lg text-lg transition-all duration-300 ease-in-out disabled:opacity-50 disabled:cursor-not-allowed shadow-lg hover:shadow-2xl hover:shadow-[var(--color-accent)]/20 disabled:shadow-none transform hover:-translate-y-1 disabled:transform-none"
                >
                    {project.isUploading ? 'Uploading...' : project.isAnalyzing ? 'Analyzing...' : project.isGenerating ? 'Generating Campaign...' : 'Generate Campaign'}
                </button>
            </div>

            {project.error && <div className="bg-[rgba(var(--color-accent-rgb),0.2)] border border-[rgba(var(--color-accent-rgb),0.5)] text-[var(--color-accent-light)] px-4 py-3 rounded-lg" role="alert">{project.error}</div>}

            {/* Results */}
            {project.results.length > 0 && (
                <div className="glass-card rounded-2xl p-4">
                     <h3 className="text-xl font-bold text-[var(--color-text-base)] mb-4">Campaign Assets (Portrait 9:16)</h3>
